import React, { useState } from "react";

export default function SavingsWithdrawScreen({ savingsBalance, onWithdraw, showNotification }) {
  const [amount, setAmount] = useState("");

  const handleWithdraw = () => {
    const value = parseFloat(amount);
    if (!value || value <= 0) {
      showNotification("Enter a valid amount", "error");
      return;
    }
    if (value > savingsBalance) {
      showNotification("Insufficient savings balance", "error");
      return;
    }
    onWithdraw(value);
    showNotification(`Withdrew $${value} from savings successfully!`, "success");
    setAmount("");
  };

  return (
    <div className="px-6 pb-24 bg-gray-50 min-h-screen">
      <h1 className="text-2xl font-bold mb-6">Withdraw from Savings</h1>
      <input
        type="number"
        placeholder="Enter amount"
        value={amount}
        onChange={(e) => setAmount(e.target.value)}
        className="w-full mb-4 p-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-red-500"
      />
      <button
        onClick={handleWithdraw}
        className="w-full bg-red-600 text-white py-3 rounded-lg hover:bg-red-700 transition-colors"
      >
        Withdraw from Savings
      </button>
    </div>
  );
}
